sql:
SELECT user_name
FROM users
WHERE user_id NOT IN (
    SELECT user_id 
    FROM user_interactions
);

SELECT name
FROM packages
WHERE price > (SELECT AVG(price) FROM packages);

SELECT COUNT(*)
FROM user_interactions
WHERE interaction_type = 'cancel';

external_knowledge:
- 'Difficulty level' is another way of referring to the 'rating'.;
- 'Related categories' are identified through the 'category_id' in the 'packages' table, which links to the 'categories' table.;
- 'Available reviews' can sometimes not exist if a package has not been reviewed, leading to null values.;

sql:
SELECT content, status
FROM promotional_content
WHERE status = 'active';

SELECT AVG(rating) AS average_rating
FROM package_reviews
WHERE package_id = 1;

SELECT package_id, COUNT(*) AS review_count
FROM package_reviews
GROUP BY package_id;
